<template>
    <div class="line-bash-container">
        <div v-for="(i,index) in data" :key="index"  class="line-bash-item">
            <img v-if="i.type === '1'" src="../assets/teamIcons/line_check.png" alt="">
            <img v-if="i.type === '0'" src="../assets/teamIcons/line_uncheck.png" alt="">
        </div>
        <div class="line-bash-text">
            {{number}}%
        </div>
    </div>
</template>

<script>

export default {

  name: "line-bash",
  props:{
    number:{
      type:Number,
      default:() => 50
    }
  },
  data() {
    return {
      cunts:0,
      dataIndex:[],
      data:[]
    }
  },
  created(){
    for (let i = 0; i < 12; i++) {
      this.data.push({
        type:'0'
      })
    }
  },
  mounted() {
    this.cunts = Math.ceil((this.number / 100)*12)
    for (let i = 0; i < this.cunts; i++) {
      this.dataIndex.push(i)
    }
    this.data.map((item,index)=>{
      if(this.dataIndex.includes(index)){
        item.type = '1'
      }else {
        item.type = '0'
      }
    })
  },

  components: {},

  methods: {}

}
</script>

<style scoped lang="scss">
    .line-bash-container {
        display: flex;
        font-family: PingFangSC-Regular, PingFang SC!important;
        .line-bash-text{
            font-size: 20px;
            margin-left: 10px;
        }
    }
</style>
