<template>
  <div class="left_middle">
    <div
      style="
        display: flex;
        flex-direction: row;
        justify-content: space-between;
        margin-bottom: 5px;
      "
    >
      <div class="title">
        <div class="title_bg"></div>
      </div>
    </div>
    <div class="content_top_border"></div>
    <div class="content">
      <div class="title">
        <div class="total" style="margin-right: 16px">任务总量</div>
        <div class="total">BUG总量</div>
      </div>
      <div class="task_analysis">
        <vue-scroll
          :data="gettersBugMonth"
          v-if="isScroll"
          class="seamless-warp"
          :class-option="classOption"
          :style="{ height: seamlessHeight + 'px' }"
        >
          <ul
            class="item task_analysis_ul"
            :style="{ height: seamlessUlHeight + 'px' }"
          >
            <li
              class="task_analysis_item"
              v-for="(item, index) in gettersBugMonth"
              :key="index"
            >
              <div class="task_analysis_left_wrap">
                <div
                  class="task_analysis_left"
                  :style="{ width: calcWidth(item, 'task') }"
                >
                  {{ item.untask }}
                </div>
              </div>
              <div class="task_analysis_center">{{ item.title }}</div>
              <div class="task_analysis_right_wrap">
                <div
                  class="task_analysis_right"
                  :style="{ width: calcWidth(item, 'bug') }"
                >
                  {{ item.unbug }}
                </div>
              </div>
            </li>
          </ul>
        </vue-scroll>
        <ul class="task_analysis_ul" v-else>
          <li
            class="task_analysis_item"
            v-for="(item, index) in gettersBugMonth"
            :key="index"
          >
            <div class="task_analysis_left_wrap">
              <div
                class="task_analysis_left"
                :style="{ width: calcWidth(item, 'task') }"
              >
                {{ item.untask }}
              </div>
            </div>
            <div class="task_analysis_center">{{ item.title }}</div>
            <div class="task_analysis_right_wrap">
              <div
                class="task_analysis_right"
                :style="{ width: calcWidth(item, 'bug') }"
              >
                {{ item.unbug }}
              </div>
            </div>
          </li>
        </ul>
      </div>
    </div>
    <div class="content_bottom_border"></div>
  </div>
</template>

<script>
import vueScroll from "vue-seamless-scroll";
import { mapGetters } from "vuex";
export default {
  name: "LeftMiddle",
  data() {
    return {
      isScroll: false,
    };
  },
  components: {
    vueScroll,
  },
  mounted() {
    setTimeout(() => {
      if (this.seamlessHeight > 172) {
        this.isScroll = true;
      } else {
        this.isScroll = false;
      }
    }, 1000);
  },
  computed: {
    ...mapGetters(["gettersBugMonth"]),
    classOption() {
      return {
        step: 0.5,
      };
    },
    seamlessHeight() {
      return this.gettersBugMonth.length * 38;
    },
    seamlessUlHeight() {
      if (this.gettersBugMonth.length < Math.ceil(172 / 38)) {
        return this.seamlessHeight;
      } else {
        return (
          this.seamlessHeight -
          this.gettersBugMonth.length +
          Math.ceil(this.gettersBugMonth.length / 10)
        );
      }
    },
  },
  methods: {
    calcWidth(data, type) {
      if (type === "task") {
        let success_task = data.untask / data.taskAll;
        return success_task >= 1
          ? 100 + "%"
          : success_task < 0.1
          ? "10%"
          : success_task * 100 + "%";
      } else if (type === "bug") {
        let success_bug = data.unbug / data.bugAll;
        return success_bug >= 1
          ? 100 + "%"
          : success_bug < 0.1
          ? "10%"
          : success_bug * 100 + "%";
      }
    },
  },
};
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped lang="scss">
