      position: absolute;
      left: -15px;
      bottom: -5px;
      width: 263px;
      height: 50px;
      background: url("../../assets/teamIcons/leftMiddle_title.png") no-repeat;
      background-size: 100% 100%;
    }
  }
  .content {
    background: linear-gradient(
      180deg,
      #04172e 0%,
